  "title": "Grundlegende Arithmetik",
  "group": "Multiplikation",
  "options": [
    {
      "text": "echo 10 * 0.5"
    },
    {
      "text": "echo (10 * 0.5)"
    },
    {
      "text": "echo ${ 10 * 0.5 }"
    },
    {
      "text": "echo %( 10 * 0.5 )"
    },
    {
      "text": "echo $(( 10 * 0.5 ))"
    },
    {
      "text": "echo '10 * 0.5' | bc"
    },
    {
      "text": "Error"
    }
  ],
  "objectives": [],
  "questionProse": [
    "Welche dieser Optionen multipliziert 10 und 0.5 korrekt und gibt 5 aus?"
  ],
  "questionCode": [],
  "hintsProse": [],
